<script>
  import { url, layout } from "@sveltech/routify";
  import marked from "marked";

  const posts = $layout.parent.children
    .filter((c) => c.meta["frontmatter"])
    .sort((a, b) => b.meta["frontmatter"].published.localeCompare(a.meta["frontmatter"].published));

  let q= '';
	$: filtered = posts.filter(item => item.meta.frontmatter.title.toLowerCase().indexOf(q.toLowerCase()) !== -1)
	
</script>


<ul class="posts" style="display: grid; place-content: center;">
<input bind:value={q} type="text" placeholder="TYPE TO FILTER">
  {#each filtered as {meta, path}}
      <li><a class="title" href={$url(path)}>{meta.frontmatter.title}</a></li>
      <!-- {@html marked(meta.frontmatter.summary)} -->
  {/each}
</ul>


